  content = '<h2>Componentes e Props em React</h2>
<p>Componentes são os blocos de construção de qualquer aplicação React. Props permitem passar dados de um componente pai para um componente filho.</p>

<h3>Tipos de Componentes</h3>
<p><strong>Componentes Funcionais:</strong> Funções JavaScript que retornam JSX</p>
<pre><code>function Botao({ label, onClick }) {
  return <button onClick={onClick}>{label}</button>;
}</code></pre>

<p><strong>Componentes de Classe:</strong> Classes que estendem React.Component (menos usado atualmente)</p>
<pre><code>class Botao extends React.Component {
  render() {
    return <button>{this.props.label}</button>;
  }
}</code></pre>

<h3>Props</h3>
<p>Props são argumentos passados para componentes. São imutáveis (read-only).</p>
<pre><code>function Card({ titulo, descricao, imagem }) {
  return (
    <div className="card">
      <img src={imagem} alt={titulo} />
      <h2>{titulo}</h2>
      <p>{descricao}</p>
    </div>
  );
}

// Uso
<Card 
  titulo="Meu Produto"
  descricao="Descrição do produto"
  imagem="/produto.jpg"
/></code></pre>

<h3>Validação de Props</h3>
<p>Use PropTypes para validar tipos de props:</p>
<pre><code>import PropTypes from "prop-types";

function Produto({ nome, preco, disponivel }) {
  return <div>{nome}: R${preco}</div>;
}

Produto.propTypes = {
  nome: PropTypes.string.isRequired,
  preco: PropTypes.number.isRequired,
  disponivel: PropTypes.bool
};</code></pre>

<h3>Props Padrão</h3>
<pre><code>function Botao({ label = "Clique aqui", tipo = "button" }) {
  return <button type={tipo}>{label}</button>;
}</code></pre>

<h3>Composição de Componentes</h3>
<p>Combine componentes para criar interfaces complexas:</p>
<pre><code>function App() {
  return (
    <div>
      <Header />
      <Sidebar />
      <MainContent />
      <Footer />
    </div>
  );
}</code></pre>

<h3>Children</h3>
<p>Props especial para conteúdo dentro de componentes:</p>
<pre><code>function Card({ children, titulo }) {
  return (
    <div className="card">
      <h2>{titulo}</h2>
      <div className="conteudo">{children}</div>
    </div>
  );
}

// Uso
<Card titulo="Meu Card">
  <p>Conteúdo aqui</p>
  <button>Ação</button>
</Card></code></pre>

<h3>Na Prática</h3>
<p>Crie componentes pequenos e reutilizáveis. Props devem ser imutáveis - se você precisa mudar dados, use state no componente pai e passe como prop.</p>',
  video_url = 'https://www.youtube.com/embed/ey7F8sA41ZI'
WHERE module_id = @react_module AND title LIKE '%Componentes%';

