UPDATE lessons SET 
  content = '<h2>Estado e Efeitos em React</h2>
<p>State permite que componentes React gerenciem dados que mudam ao longo do tempo. Efeitos permitem realizar ações colaterais como buscar dados da API.</p>

<h3>useState Hook</h3>
<p>Hook mais importante do React. Permite adicionar state a componentes funcionais.</p>
<pre><code>import { useState } from "react";

function Contador() {
  const [count, setCount] = useState(0);
  const [nome, setNome] = useState("");

  return (
    <div>
      <p>Contagem: {count}</p>
      <button onClick={() => setCount(count + 1)}>+1</button>

      <input 
        value={nome}
        onChange={(e) => setNome(e.target.value)}
      />
      <p>Nome: {nome}</p>
    </div>
  );
}</code></pre>

<h3>useEffect Hook</h3>
<p>Permite executar efeitos colaterais (buscar dados, atualizar DOM, etc):</p>
<pre><code>import { useEffect, useState } from "react";

function Usuario({ id }) {
  const [usuario, setUsuario] = useState(null);
  const [carregando, setCarregando] = useState(true);

  useEffect(() => {
    setCarregando(true);
    fetch(`/api/usuarios/${id}`)
      .then(res => res.json())
      .then(dados => {
        setUsuario(dados);
        setCarregando(false);
      });
  }, [id]); // Dependência: reexecuta quando id muda

  if (carregando) return <p>Carregando...</p>;
  return <div>{usuario.nome}</div>;
}</code></pre>

<h3>Array de Dependências</h3>
<p>Controla quando o efeito é executado:</p>
<pre><code>// Executa uma única vez (montagem)
useEffect(() => {
  console.log("Componente montado");
}, []);

// Executa sempre que count muda
useEffect(() => {
  console.log("Count mudou para:", count);
}, [count]);

// Executa sempre que o componente renderiza
useEffect(() => {
  console.log("Renderizou");
});</code></pre>

<h3>Limpeza de Efeitos</h3>
<p>Retorne uma função de limpeza para evitar vazamento de memória:</p>
<pre><code>useEffect(() => {
  const intervalo = setInterval(() => {
    console.log("Tick");
  }, 1000);

  // Limpeza
  return () => clearInterval(intervalo);
}, []);</code></pre>

<h3>Múltiplos Estados</h3>
<pre><code>function Formulario() {
  const [formData, setFormData] = useState({
    nome: "",
    email: "",
    senha: ""
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  return (
    <form>
      <input name="nome" value={formData.nome} onChange={handleChange} />
      <input name="email" value={formData.email} onChange={handleChange} />
      <input name="senha" type="password" value={formData.senha} onChange={handleChange} />
    </form>
  );
}</code></pre>

<h3>Na Prática</h3>
<p>Use useState para dados que mudam, useEffect para buscar dados e efeitos colaterais. Sempre especifique o array de dependências para evitar loops infinitos.</p>',
  video_url = 'https://www.youtube.com/embed/O6P86XQ5kQ4'
WHERE module_id = @react_module AND title LIKE '%Estado%';

